// ============================================================
// CONFIGURATION  edit all parameters here
// ============================================================

const DEVICE_ID = 'b6930861fd4fcd8ce162a7643da311f5';

// Default mode: schedule time slots.
// Each slot: { startHour, endHour, maxA }
// startHour inclusive, endHour exclusive (24-hour format).
// maxA = the guaranteed minimum charging speed within this window.
// If solar is exporting, the current can rise above maxA (up to SOLAR_MAX_A).
const SCHEDULE_WEEKDAY = [
    { startHour: 1, endHour: 7, maxA: 16 }
];

const SCHEDULE_WEEKEND = [
    { startHour: 1,  endHour: 7,  maxA: 16 },
    { startHour: 11, endHour: 17, maxA: 16 }
];

// Absolute maximum that solar surplus may ramp up to in Default mode.
const SOLAR_MAX_A = 32;

// Maximum current for Boost mode (session-only).
const BOOST_MAX_A = 32;

// Solar only mode: current range (session-only).
// Min = 0 so the car pauses completely when no solar is available.
const SOLAR_ONLY_MIN_A = 0;
const SOLAR_ONLY_MAX_A = 32;

// Dead-band in watts before we adjust the current by 1 A.
// ~400 W  1.7 A on a single 230 V phase  prevents oscillation.
const SOLAR_MARGIN_W = 400;

// ============================================================
// LOGIC  no need to edit below this line
// ============================================================

const mode     = msg.mode;
const p1       = Number(msg.p1_power);        // W, positive = importing, negative = exporting
let   setpoint = Number(msg.current_setpoint); // A

if (isNaN(p1) || isNaN(setpoint)) {
    node.warn('Invalid P1 or setpoint  skipping tick');
    return null;
}

function isWeekend() {
    const d = new Date().getDay(); // 0=Sun, 6=Sat
    return d === 0 || d === 6;
}

function activeSlot(slots) {
    const now  = new Date();
    const hour = now.getHours() + now.getMinutes() / 60;
    return slots.find(s => hour >= s.startHour && hour < s.endHour) || null;
}

function clamp(v, min, max) {
    return Math.max(min, Math.min(max, Math.round(v)));
}

// --- Default mode: schedule-following + solar ramp-up ---
// Outside every schedule window                 0 A (car pauses).
// Inside a window, floor = slot.maxA:
//   exporting solar (p1 < -margin)              ramp up toward SOLAR_MAX_A
//   importing AND already above floor (p1 > margin)  ramp back down toward floor
//   otherwise                                   keep setpoint unchanged
if (mode === 'Default') {
    const schedule = isWeekend() ? SCHEDULE_WEEKEND : SCHEDULE_WEEKDAY;
    const slot     = activeSlot(schedule);
    if (!slot) {
        // Outside every window  stop charging
        msg.payload = { new_current: 0, device_id: DEVICE_ID };
    } else {
        let newA = setpoint;
        if      (p1 < -SOLAR_MARGIN_W)               newA += 1; // solar surplus  speed up
        else if (p1 >  SOLAR_MARGIN_W && newA > slot.maxA) newA -= 1; // importing + above floor  slow down
        newA = clamp(newA, slot.maxA, SOLAR_MAX_A);
        msg.payload = { new_current: newA, device_id: DEVICE_ID };
    }
    return msg;
}

// --- Boost mode (session-only) ---
// Charges at BOOST_MAX_A immediately, ignoring schedule and solar.
// Automatically resets to Default when the car unplugs.
if (mode === 'Boost') {
    msg.payload = { new_current: BOOST_MAX_A, device_id: DEVICE_ID };
    return msg;
}

// --- Solar only mode (session-only) ---
// Tracks solar export; pauses (0 A) when no solar is available.
// Automatically resets to Default when the car unplugs.
if (mode === 'Solar only') {
    let newA = setpoint;
    if      (p1 < -SOLAR_MARGIN_W) newA += 1; // exporting  speed up
    else if (p1 >  SOLAR_MARGIN_W) newA -= 1; // importing  slow down
    newA = clamp(newA, SOLAR_ONLY_MIN_A, SOLAR_ONLY_MAX_A);
    msg.payload = { new_current: newA, device_id: DEVICE_ID };
    return msg;
}

node.warn('Unknown mode: ' + mode);
return null;
